patches.fixed_method:
public void noMoreInteractionsWanted(Invocation undesired, List<VerificationAwareInvocation> invocations) {
    ScenarioPrinter scenarioPrinter = new ScenarioPrinter();
    String scenario = scenarioPrinter.print(invocations);

    Object mock = undesired.getMock();
    String mockDescription;
    if (mock == null) {
        mockDescription = "null";
    } else {
        try {
            String mockToString = mock.toString();
            if (mockToString != null && !mockToString.equals(mock.getClass().getName())) {
                mockDescription = mockToString;
            } else {
                throw new IllegalStateException("Mock object does not have a proper toString implementation: " + mock.getClass().getName());
            }
        } catch (Exception e) {
            mockDescription = mock.getClass().getName();
        }
    }

    throw new NoInteractionsWanted(join(
            "No interactions wanted here:",
            new LocationImpl(),
            "But found this interaction on mock '" + mockDescription + "':",
            undesired.getLocation(),
            scenario
    ));
}
